DROP VIEW "catalog"."product_list_view";--> statement-breakpoint
CREATE VIEW "catalog"."product_list_view" AS (select "catalog"."product"."project_id", "catalog"."product"."id", "catalog"."product"."vendor_id", "catalog"."product"."handle", "catalog"."product"."published_at", "catalog"."product"."created_at", "catalog"."product"."updated_at", "catalog"."product"."deleted_at", "catalog"."product"."revision", "catalog"."product_translation"."locale", "catalog"."product_translation"."name", "product_price_range"."currency", "min_amount_minor" as "min_price_minor", "max_amount_minor" as "max_price_minor", "catalog"."product_category"."category_id" as "primary_category_id", "catalog"."category_translation"."name" as "primary_category_name", "catalog"."product_feature_value_translation"."name" as "brand_name" from "catalog"."product" inner join "catalog"."product_translation" on "catalog"."product_translation"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_translation"."product_id" = "catalog"."product"."id" left join "catalog"."product_price_range" on "product_price_range"."project_id" = "catalog"."product"."project_id" AND "product_price_range"."product_id" = "catalog"."product"."id" left join "catalog"."product_category" on "catalog"."product_category"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_category"."product_id" = "catalog"."product"."id" AND "catalog"."product_category"."is_primary" = true left join "catalog"."category_translation" on "catalog"."category_translation"."project_id" = "catalog"."product"."project_id" AND "catalog"."category_translation"."category_id" = "catalog"."product_category"."category_id" AND "catalog"."category_translation"."locale" = "catalog"."product_translation"."locale" left join "catalog"."product_feature" on "catalog"."product_feature"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_feature"."product_id" = "catalog"."product"."id" AND "catalog"."product_feature"."slug" = 'brand' left join "catalog"."product_feature_value" on "catalog"."product_feature_value"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_feature_value"."feature_id" = "catalog"."product_feature"."id" AND "catalog"."product_feature_value"."index" = 0 left join "catalog"."product_feature_value_translation" on "catalog"."product_feature_value_translation"."project_id" = "catalog"."product"."project_id" AND "catalog"."product_feature_value_translation"."feature_value_id" = "catalog"."product_feature_value"."id" AND "catalog"."product_feature_value_translation"."locale" = "catalog"."product_translation"."locale");